// ── Hono sub-app for /blog/* routes ──
export const blogRouter = new Hono<{ Bindings: Env }>();

// Blog index
blogRouter.get("/", (c) => {
  return c.html(blogIndexHTML());
});

// Sitemap
blogRouter.get("/sitemap.xml", async (c) => {
  const urls = manifest.map(e =>
    `  <url><loc>https://darcloud.host/blog/${e.slug}</loc><changefreq>weekly</changefreq><priority>0.7</priority></url>`
  ).join('\n');
  const xml = `<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
  <url><loc>https://darcloud.host/blog</loc><changefreq>daily</changefreq><priority>0.9</priority></url>
${urls}
</urlset>`;
  return new Response(xml, {
    headers: { "Content-Type": "application/xml", "Cache-Control": "public, max-age=3600" },
  });
});

// RSS Feed
blogRouter.get("/feed.xml", (c) => {
  const items = manifest.slice(0, 50).map(e =>
    `    <item>
      <title>${e.slug.replace(/-/g, ' ')}</title>
      <link>https://darcloud.host/blog/${e.slug}</link>
      <guid>https://darcloud.host/blog/${e.slug}</guid>
    </item>`
  ).join('\n');
  const xml = `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0">
  <channel>
    <title>DarCloud Blog</title>
    <link>https://darcloud.host/blog</link>
    <description>Islamic Tech, AI, Blockchain &amp; Halal Economy</description>
${items}
  </channel>
</rss>`;
  return new Response(xml, {
    headers: { "Content-Type": "application/rss+xml", "Cache-Control": "public, max-age=3600" },
  });
});

// Category page
blogRouter.get("/category/:cat", (c) => {
  const cat = c.req.param("cat");
  const exists = manifest.some(e => e.cat === cat);
  if (!exists) {
    return c.html(notFoundHTML(), 404);
  }
  return c.html(categoryPageHTML(cat));
});

// Individual blog post — serve inline-generated content
blogRouter.get("/:slug", (c) => {
  const slug = c.req.param("slug");
  if (!/^[a-z0-9-]+$/.test(slug)) {
    return c.html(notFoundHTML(), 404);
  }
  const entry = manifest.find(e => e.slug === slug);
  if (!entry) {
    return c.html(notFoundHTML(), 404);
  }
  return c.html(generateInlinePost(entry));
});

