// ── Blog subdomain handler (blog.darcloud.host) ──
export const blogSubdomainPage = {
  async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url);
    const path = url.pathname;

    if (request.method === "OPTIONS") {
      return new Response(null, { status: 204 });
    }

    if (path === "/health") {
      return Response.json({ status: "healthy", service: "blog", posts: manifest.length });
    }

    if (path === "/sitemap.xml") {
      const urls = manifest.map(e =>
        `  <url><loc>https://blog.darcloud.host/${e.slug}</loc><changefreq>weekly</changefreq><priority>0.7</priority></url>`
      ).join('\n');
      return new Response(`<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
  <url><loc>https://blog.darcloud.host/</loc><changefreq>daily</changefreq><priority>1.0</priority></url>
${urls}
</urlset>`, { headers: { "Content-Type": "application/xml" } });
    }

    const catMatch = path.match(/^\/category\/([a-z0-9-]+)\/?$/);
    if (catMatch) {
      const exists = manifest.some(e => e.cat === catMatch[1]);
      if (exists) {
        return new Response(categoryPageHTML(catMatch[1]), {
          headers: { "Content-Type": "text/html;charset=utf-8" },
        });
      }
    }

    const slugMatch = path.match(/^\/([a-z0-9-]+)\/?$/);
    if (slugMatch && slugMatch[1] !== 'favicon.ico') {
      const entry = manifest.find(e => e.slug === slugMatch[1]);
      if (entry) {
        return new Response(generateInlinePost(entry), {
          headers: { "Content-Type": "text/html;charset=utf-8" },
        });
      }
    }

    return new Response(blogIndexHTML(), {
      headers: { "Content-Type": "text/html;charset=utf-8" },
    });
  }
};
